# =============================================================================
# AST Nodes
# =============================================================================

class ASTNode:
    pass


class SignalRef(ASTNode):
    """Reference to a signal with optional slice/index.

    name: signal name
    msb: None for scalar reference, otherwise MSB of slice/index
    lsb: None for scalar reference, LSB of slice (for single bit, msb=lsb)
    """
    def __init__(self, name: str, msb: Optional[int] = None, lsb: Optional[int] = None):
        self.name = name
        self.msb = msb
        self.lsb = lsb

    def __repr__(self):
        if self.msb is None:
            return f"SignalRef({self.name})"
        elif self.msb == self.lsb:
            return f"SignalRef({self.name}[{self.msb}])"
        else:
            return f"SignalRef({self.name}[{self.msb}:{self.lsb}])"


class Literal(ASTNode):
    """Literal value with width.

    value: integer value
    width: bit width
    """
    def __init__(self, value: int, width: int):
        self.value = value
        self.width = width

    def __repr__(self):
        return f"Literal(0b{self.value:0{self.width}b}, width={self.width})"


class Concat(ASTNode):
    """Concatenation: {e1, e2, ..., ek}"""
    def __init__(self, parts: List[ASTNode]):
        self.parts = parts

    def __repr__(self):
        return f"Concat([{', '.join(repr(p) for p in self.parts)}])"


class OpCall(ASTNode):
    """Operator call: OP(arg1, arg2, ...)"""
    def __init__(self, op: str, args: List[ASTNode]):
        self.op = op
        self.args = args

    def __repr__(self):
        return f"OpCall({self.op}, [{', '.join(repr(a) for a in self.args)}])"


# =============================================================================
# Signal Declaration
# =============================================================================

class SignalDecl:
    """Signal declaration with width information.

    name: signal name
    sig_type: 'input', 'output', or 'wire'
    msb: MSB of the signal (None for scalar in old format)
    lsb: LSB of the signal (None for scalar in old format)
    """
    def __init__(self, name: str, sig_type: str, msb: Optional[int] = None, lsb: Optional[int] = None):
        self.name = name
        self.sig_type = sig_type
        self.msb = msb
        self.lsb = lsb

    @property
    def width(self) -> int:
        if self.msb is None:
            return 1
        return self.msb - self.lsb + 1

    def __repr__(self):
        if self.msb is None:
            return f"SignalDecl({self.name}, {self.sig_type})"
        return f"SignalDecl({self.name}[{self.msb}:{self.lsb}], {self.sig_type})"


# =============================================================================
# Token Types
# =============================================================================

TOKEN_ID = 'ID'
TOKEN_KW = 'KW'
TOKEN_OP = 'OP'
TOKEN_LITERAL = 'LITERAL'
TOKEN_NUMBER = 'NUMBER'
TOKEN_LBRACE = '{'
TOKEN_RBRACE = '}'
TOKEN_LBRACK = '['
TOKEN_RBRACK = ']'
TOKEN_COLON = ':'
TOKEN_EQ = '='
TOKEN_COMMA = ','
TOKEN_LPAREN = '('
TOKEN_RPAREN = ')'
TOKEN_EOF = 'EOF'


class Token:
    def __init__(self, type: str, value: str, line: int, col: int):
        self.type = type
        self.value = value
        self.line = line
        self.col = col

    def __repr__(self):
        return f"Token({self.type}, {self.value!r}, line={self.line}, col={self.col})"


# =============================================================================
# Lexer
# =============================================================================

def tokenize(line: str, line_num: int) -> List[Token]:
    """Tokenize a single line.

    Returns list of Token objects.
    """
    tokens = []
    pos = 0
    length = len(line)

    # Operator patterns (case-insensitive)
    operators = {'AND', 'OR', 'XOR', 'NAND', 'NOR', 'XNOR', 'NOT', 'BUF',
                 'MUX', 'ITE', 'REDUCE_AND', 'REDUCE_OR', 'REDUCE_XOR', 'EQ'}

    while pos < length:
        col_pos = pos + 1  # 1-based column

        # Skip whitespace
        if line[pos] in ' \t':
            pos += 1
            continue

        # Comment
        if line[pos] == '#':
            break  # Rest of line is comment, ignore

        # Identifiers (letters, underscores, digits after first char)
        if re.match(r'[a-zA-Z_]', line[pos:]):
            match = re.match(r'[a-zA-Z_][a-zA-Z0-9_]*', line[pos:])
            if match:
                token = match.group()
                upper_token = token.upper()
                if upper_token in operators:
                    tokens.append(Token(TOKEN_OP, upper_token, line_num, col_pos))
                elif upper_token in {'INPUT', 'OUTPUT', 'WIRE'}:
                    tokens.append(Token(TOKEN_KW, upper_token, line_num, col_pos))
                else:
                    tokens.append(Token(TOKEN_ID, token, line_num, col_pos))
                pos += len(token)
                continue

        # Numbers (decimal integers for msb:lsb notation)
        if re.match(r'[0-9]', line[pos:]):
            match = re.match(r'[0-9]+', line[pos:])
            if match:
                tokens.append(Token(TOKEN_NUMBER, match.group(), line_num, col_pos))
                pos += len(match.group())
                continue

        # Literals: 0, 1 (scalar), sized/unsized vectors
        if line[pos] in '01':
            # Check if this is a sized literal like 8'b1010
            rest = line[pos:]
            sized_match = re.match(r'(\d+)\'[bBhHdD]([\d01a-fA-F_]+)', rest)
            if sized_match:
                # This is a sized literal
                width = int(sized_match.group(1))
                radix_str = sized_match.group(2).lower()
                value_str = sized_match.group(3).replace('_', '')

                # Parse based on radix
                if radix_str in ('b', 'h', 'd'):
                    try:
                        radix_map = {'b': 2, 'h': 16, 'd': 10}
                        value = int(value_str, radix_map[radix_str])
                    except ValueError:
                        raise CircParseError(
                            f"Invalid literal: {sized_match.group(0)}",
                            file=None, line=line_num, col=col_pos
                        )

                    # Check value fits in width
                    if value >= (1 << width):
                        raise CircParseError(
                            f"Value {value} too large for {width}-bit literal",
                            file=None, line=line_num, col=col_pos
                        )

                    tokens.append(Token(TOKEN_LITERAL, f"{width}'{radix_str}{value_str}", line_num, col_pos))
                    pos += len(sized_match.group(0))
                    continue
            else:
                # Scalar literal
                tokens.append(Token(TOKEN_LITERAL, line[pos], line_num, col_pos))
                pos += 1
                continue

        # Check for 0b or 0x binary/hex literals
        if line[pos:pos+2] in ('0b', '0x'):
            prefix = line[pos:pos+2]
            rest = line[pos+2:]
            # Must have at least one digit after prefix
            match = re.match(r'[0-9a-fA-F]+', rest)
            if match:
                digits = match.group()
                tokens.append(Token(TOKEN_LITERAL, f"{prefix}{digits}", line_num, col_pos))
                pos += 2 + len(digits)
                continue
            else:
                raise CircParseError(
                    f"Binary/hex literal must have at least one digit",
                    file=None, line=line_num, col=col_pos
                )

        # Braces and brackets
        if line[pos] in '{}[]':
            tokens.append(Token(line[pos], line[pos], line_num, col_pos))
            pos += 1
            continue

        # Colon
        if line[pos] == ':':
            tokens.append(Token(TOKEN_COLON, ':', line_num, col_pos))
            pos += 1
            continue

        # Comma
        if line[pos] == ',':
            tokens.append(Token(TOKEN_COMMA, ',', line_num, col_pos))
            pos += 1
            continue

        # Equals sign
        if line[pos] == '=':
            tokens.append(Token(TOKEN_EQ, '=', line_num, col_pos))
            pos += 1
            continue

        # Parentheses
        if line[pos] in '()':
            type_map = {'(': TOKEN_LPAREN, ')': TOKEN_RPAREN}
            tokens.append(Token(type_map[line[pos]], line[pos], line_num, col_pos))
            pos += 1
            continue

        # Unknown character
        raise CircParseError(
            f"Unexpected character: {line[pos]}",
            file=None, line=line_num, col=col_pos
        )

    tokens.append(Token(TOKEN_EOF, '', line_num, len(line) + 1))
    return tokens


# =============================================================================
# Parser
# =============================================================================

class Parser:
    """Parser for circuit expressions."""

    def __init__(self, tokens: List[Token], filepath: str):
        self.tokens = tokens
        self.filepath = filepath
        self.pos = 0

    def peek(self) -> Token:
        return self.tokens[self.pos]

    def consume(self, expected_type: Optional[str] = None,
                expected_value: Optional[str] = None) -> Token:
        tok = self.peek()
        if expected_type is not None and tok.type != expected_type:
            raise self.error(f"Expected token type {expected_type}, got {tok.type}")
        if expected_value is not None and tok.value != expected_value:
            raise self.error(f"Expected {expected_value}, got {tok.value}")
        self.pos += 1
        return tok

    def error(self, message: str) -> CircParseError:
        tok = self.peek()
        return CircParseError(
            message,
            file=self.filepath,
            line=tok.line,
            col=tok.col
        )

    def parse_expression(self) -> ASTNode:
        """Parse an expression: concatenation, signal ref, literal, or op call."""
        tok = self.peek()

        # If it's an identifier followed by [, it's a slice/index
        if tok.type == TOKEN_ID:
            name = tok.value
            self.consume(TOKEN_ID)

            # Check for slice or index
            if self.peek().type == TOKEN_LBRACK:
                return self.parse_signal_ref_with_select(name)
            else:
                return SignalRef(name)

        elif tok.type == TOKEN_LITERAL:
            return self.parse_literal()

        elif tok.type == TOKEN_LBRACE:
            # Concatenation: {e1, e2, ...}
            return self.parse_concat()

        elif tok.type == TOKEN_OP:
            # Operator call: OP(...)
            return self.parse_op_call()

        else:
            raise self.error(f"Unexpected token in expression: {tok.value}")

    def parse_signal_ref_with_select(self, name: str) -> SignalRef:
        """Parse a signal reference with optional slice/index: v[i] or v[hi:lo]"""
        self.consume(TOKEN_LBRACK)

        # Parse first number (msb or index)
        if self.peek().type != TOKEN_NUMBER:
            raise self.error("Expected number in slice/index")
        msb_val = int(self.consume().value)

        # Check if it's a slice (with colon) or single bit index
        if self.peek().type == TOKEN_COLON:
            self.consume(TOKEN_COLON)  # consume ':'

            # Parse lsb
            if self.peek().type != TOKEN_NUMBER:
                raise self.error("Expected number after colon in slice")
            lsb_val = int(self.consume().value)

            self.consume(TOKEN_RBRACK)

            # Validate: msb >= lsb >= 0
            if msb_val < lsb_val:
                raise self.error(f"Invalid slice: msb ({msb_val}) < lsb ({lsb_val})")
            if lsb_val < 0:
                raise self.error(f"Invalid slice: lsb ({lsb_val}) < 0")

            return SignalRef(name, msb_val, lsb_val)
        else:
            # Single bit index
            self.consume(TOKEN_RBRACK)
            return SignalRef(name, msb_val, msb_val)  # msb=lsb for single bit

    def parse_literal(self) -> Literal:
        """Parse a literal value."""
        tok = self.consume(TOKEN_LITERAL)
        val = tok.value

        if val in ('0', '1'):
            return Literal(int(val), 1)
        elif val.startswith('0b'):
            # Binary literal: 0b1101
            bits = val[2:]
            if not bits:
                raise self.error("Binary literal must have at least one digit")
            value = int(bits, 2)
            return Literal(value, len(bits))
        elif val.startswith('0x'):
            # Hex literal: 0x0f
            hex_digits = val[2:]
            if not hex_digits:
                raise self.error("Hex literal must have at least one digit")
            value = int(hex_digits, 16)
            return Literal(value, len(hex_digits) * 4)
        else:
            # Sized literal: 8'b1010, 8'hff, 8'd200
            match = re.match(r'(\d+)\'[bBhHdD]([\d01a-fA-F_]+)', val)
            if match:
                width = int(match.group(1))
                radix_str = match.group(2).lower()
                value_str = match.group(3).replace('_', '')

                try:
                    radix_map = {'b': 2, 'h': 16, 'd': 10}
                    value = int(value_str, radix_map[radix_str])
                except ValueError:
                    raise self.error(f"Invalid literal: {val}")

                if value >= (1 << width):
                    raise self.error(f"Value {value} too large for {width}-bit literal")

                return Literal(value, width)
            else:
                raise self.error(f"Invalid literal format: {val}")

    def parse_concat(self) -> Concat:
        """Parse concatenation: {e1, e2, ...}"""
        self.consume(TOKEN_LBRACE)

        parts = []
        while True:
            if self.peek().type == TOKEN_RBRACE:
                break

            parts.append(self.parse_expression())

            if self.peek().type == TOKEN_COMMA:
                self.consume(TOKEN_COMMA)
                continue
            elif self.peek().type == TOKEN_RBRACE:
                break

        self.consume(TOKEN_RBRACE)
        return Concat(parts)

    def parse_op_call(self) -> OpCall:
        """Parse operator call: OP(arg1, arg2, ...)"""
        op_tok = self.consume(TOKEN_OP)
        op = op_tok.value

        self.consume(TOKEN_LPAREN)

        args = []
        while True:
            if self.peek().type == TOKEN_RPAREN:
                break

            args.append(self.parse_expression())

            if self.peek().type == TOKEN_COMMA:
                self.consume(TOKEN_COMMA)
                continue
            elif self.peek().type == TOKEN_RPAREN:
                break

        self.consume(TOKEN_RPAREN)
        return OpCall(op, args)

    def parse_assignment_line(self) -> Tuple[str, ASTNode]:
        """Parse an assignment line: lhs = expression"""
        # Parse LHS (identifier)
        lhs_tok = self.consume(TOKEN_ID)
        lhs = lhs_tok.value

        self.consume(TOKEN_EQ)

        # Parse RHS expression
        expr = self.parse_expression()

        # Make sure we're at EOF
        if self.peek().type != TOKEN_EOF:
            raise self.error(f"Unexpected token after expression: {self.peek().value}")

        return lhs, expr

    def parse_declaration(self) -> List[SignalDecl]:
        """Parse a declaration line: INPUT/OUTPUT/WIRE name[msb:lsb]"""
        kw_tok = self.consume(TOKEN_KW)
        decl_type = kw_tok.value.lower()

        decls = []
        while True:
            # Parse identifier
            id_tok = self.consume(TOKEN_ID)
            name = id_tok.value

            # Check for width specifier
            msb = None
            lsb = None
            if self.peek().type == TOKEN_LBRACK:
                self.consume(TOKEN_LBRACK)

                # Parse msb
                if self.peek().type != TOKEN_NUMBER:
                    raise self.error(f"Expected number after [ for {name}")
                msb = int(self.consume().value)

                # Check for slice or single bit
                if self.peek().type == TOKEN_COLON:
                    self.consume(TOKEN_COLON)

                    if self.peek().type != TOKEN_NUMBER:
                        raise self.error(f"Expected number after : for {name}")
                    lsb = int(self.consume().value)

                    if msb < lsb:
                        raise self.error(f"Invalid range for {name}: msb ({msb}) < lsb ({lsb})")
                    if lsb < 0:
                        raise self.error(f"Invalid range for {name}: lsb ({lsb}) < 0")
                else:
                    # Single bit - msb=lsb
                    lsb = msb

                self.consume(TOKEN_RBRACK)

            decls.append(SignalDecl(name, decl_type, msb, lsb))

            # Check for more names or end of line
            if self.peek().type == TOKEN_EOF:
                break
            elif self.peek().type == TOKEN_COMMA:
                self.consume(TOKEN_COMMA)
                continue
            elif self.peek().type == TOKEN_ID:
                # Another identifier directly - continue to consume it
                continue
            else:
                raise self.error(f"Unexpected token: {self.peek().value}")

        return decls


def parse_circ_file(filepath: str) -> Tuple[List[SignalDecl], List[Tuple[str, ASTNode]]]:
    """Parse a .circ file and return (declarations, assignments).

    Returns:
        declarations: List of SignalDecl objects
        assignments: List of (lhs, expression) tuples
    """
    with open(filepath, 'r') as f:
        lines = f.readlines()

    declarations = []
    assignments = []
    seen_assignment = False

    for line_num, line in enumerate(lines, 1):
        line = line.rstrip('\n\r')

        # Skip empty lines and comments
        stripped = line.lstrip()
        if not stripped or stripped.startswith('#'):
            continue

        try:
            tokens = tokenize(line, line_num)
        except CircParseError as e:
            if e.file is None:
                e.file = filepath
            raise

        if not tokens:
            continue

        parser = Parser(tokens, filepath)

        # Check if it's a declaration
        if tokens[0].type == TOKEN_KW:
            # Declaration line
            if seen_assignment:
                raise DeclarationAfterAssignmentError(
                    f"Declaration found after assignment",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            try:
                decls = parser.parse_declaration()
                declarations.extend(decls)
            except CircParseError as e:
                if e.file is None:
                    e.file = filepath
                raise

        elif tokens[0].type == TOKEN_ID:
            # Assignment line
            seen_assignment = True

            try:
                lhs, expr = parser.parse_assignment_line()
                assignments.append((lhs, expr))
            except CircParseError as e:
                if e.file is None:
                    e.file = filepath
                raise
        else:
            raise CircParseError(
                f"Expected keyword (input/output/wire) or identifier",
                file=filepath,
                line=line_num,
                col=1
            )

    return declarations, assignments


# =============================================================================
# JSON Circuit Format Parser
# =============================================================================

def parse_json_file(filepath: str) -> Tuple[List[SignalDecl], List[Tuple[str, ASTNode]]]:
    """Parse a JSON circuit file and return (declarations, assignments).

    Returns:
        declarations: List of SignalDecl objects
        assignments: List of (lhs, expression) tuples

    Raises:
        JsonParseError: Invalid JSON syntax
        JsonSchemaError: JSON doesn't match expected schema
        CircParseError: Expression parsing error
    """
    with open(filepath, 'r') as f:
        try:
            data = json.load(f)
        except json.JSONDecodeError as e:
            raise JsonParseError(
                f"Invalid JSON syntax: {e}",
                file=filepath,
                line=e.lineno,
                col=e.colno
            )

    # Validate schema
    if not isinstance(data, dict):
        raise JsonSchemaError(
            "JSON root must be an object",
            file=filepath
        )

    required_keys = {'format_version', 'inputs', 'outputs', 'wires', 'assignments'}
    missing = required_keys - set(data.keys())
    if missing:
        raise JsonSchemaError(
            f"Missing required keys: {', '.join(sorted(missing))}",
            file=filepath
        )

    # Check format_version
    if data['format_version'] != 1:
        raise JsonSchemaError(
            f"Unsupported format_version: {data['format_version']}. Expected 1.",
            file=filepath
        )

    # Helper to validate port object
    def validate_port(port: dict, key_name: str) -> dict:
        if not isinstance(port, dict):
            raise JsonSchemaError(
                f"{key_name} must be an array of objects",
                file=filepath
            )
        if 'name' not in port:
            raise JsonSchemaError(
                f"Port object missing 'name' field",
                file=filepath
            )
        msb = port.get('msb')
        lsb = port.get('lsb')

        if msb is None and lsb is None:
            # Scalar port - valid
            return port

        if not isinstance(msb, int) or not isinstance(lsb, int):
            raise JsonSchemaError(
                f"Port '{port.get('name', '?')}': msb and lsb must be integers",
                file=filepath
            )

        if msb < lsb:
            raise JsonSchemaError(
                f"Port '{port['name']}': msb ({msb}) < lsb ({lsb})",
                file=filepath
            )

        if lsb < 0:
            raise JsonSchemaError(
                f"Port '{port['name']}': lsb ({lsb}) < 0",
                file=filepath
            )

        return port

    # Parse inputs
    inputs_list = data['inputs']
    if not isinstance(inputs_list, list):
        raise JsonSchemaError(
            "'inputs' must be an array",
            file=filepath
        )

    declarations: List[SignalDecl] = []
    seen_names: Set[str] = set()

    for i, port in enumerate(inputs_list):
        validate_port(port, f"inputs[{i}]")
        name = port['name']
        if name in seen_names:
            raise DuplicateNameError(
                f"Duplicate input name: {name}",
                file=filepath
            )
        seen_names.add(name)

        msb = port.get('msb')
        lsb = port.get('lsb')
        # Convert None/None to None, None for scalar; otherwise keep values
        msb_val = msb if msb is not None else None
        lsb_val = lsb if lsb is not None else None
        declarations.append(SignalDecl(name, 'input', msb_val, lsb_val))

    # Parse outputs
    outputs_list = data['outputs']
    if not isinstance(outputs_list, list):
        raise JsonSchemaError(
            "'outputs' must be an array",
            file=filepath
        )

    for i, port in enumerate(outputs_list):
        validate_port(port, f"outputs[{i}]")
        name = port['name']
        if name in seen_names:
            raise DuplicateNameError(
                f"Duplicate output name: {name}",
                file=filepath
            )
        seen_names.add(name)

        msb = port.get('msb')
        lsb = port.get('lsb')
        msb_val = msb if msb is not None else None
        lsb_val = lsb if lsb is not None else None
        declarations.append(SignalDecl(name, 'output', msb_val, lsb_val))

    # Parse wires
    wires_list = data['wires']
    if not isinstance(wires_list, list):
        raise JsonSchemaError(
            "'wires' must be an array",
            file=filepath
        )

    for i, port in enumerate(wires_list):
        validate_port(port, f"wires[{i}]")
        name = port['name']
        if name in seen_names:
            raise DuplicateNameError(
                f"Duplicate wire name: {name}",
                file=filepath
            )
        seen_names.add(name)

        msb = port.get('msb')
        lsb = port.get('lsb')
        msb_val = msb if msb is not None else None
        lsb_val = lsb if lsb is not None else None
        declarations.append(SignalDecl(name, 'wire', msb_val, lsb_val))

    # Parse assignments
    assignments_list = data['assignments']
    if not isinstance(assignments_list, list):
        raise JsonSchemaError(
            "'assignments' must be an array",
            file=filepath
        )

    assignments: List[Tuple[str, ASTNode]] = []
    lhs_seen: Set[str] = set()

    for i, assn in enumerate(assignments_list):
        if not isinstance(assn, dict):
            raise JsonSchemaError(
                f"assignments[{i}] must be an object",
                file=filepath
            )
        if 'lhs' not in assn:
            raise JsonSchemaError(
                f"assignments[{i}] missing 'lhs' field",
                file=filepath
            )
        if 'rhs' not in assn:
            raise JsonSchemaError(
                f"assignments[{i}] missing 'rhs' field",
                file=filepath
            )

        lhs = assn['lhs']
        rhs_str = assn['rhs']

        if not isinstance(lhs, str):
            raise JsonSchemaError(
                f"assignments[{i}].lhs must be a string",
                file=filepath
            )
        if not isinstance(rhs_str, str):
            raise JsonSchemaError(
                f"assignments[{i}].rhs must be a string",
                file=filepath
            )

        if lhs in lhs_seen:
            raise RedefinitionError(
                f"Signal '{lhs}' defined multiple times",
                file=filepath
            )
        lhs_seen.add(lhs)

        # Parse RHS expression using existing expression parser
        # Create a temporary tokens list by tokenizing the expression string
        # We'll reuse the existing tokenize function by creating a mock line
        try:
            tokens = tokenize(rhs_str, 1)  # line 1 for expression error context
        except CircParseError as e:
            # Adjust line/col to point to the assignment
            raise CircParseError(
                f"Error in assignment {i}: {e.message}",
                file=filepath,
                line=None,
                col=None
            )

        parser = Parser(tokens, filepath)
        try:
            expr = parser.parse_expression()
        except CircParseError as e:
            raise CircParseError(
                f"Error in assignment {i}: {e.message}",
                file=filepath
            )

        # Ensure we consumed all tokens (no trailing junk)
        if parser.peek().type != TOKEN_EOF:
            raise CircParseError(
                f"Unexpected token after expression in assignment {i}",
                file=filepath
            )

        assignments.append((lhs, expr))

    # Validate that every wire and output appears exactly once as assignment LHS
    wire_names = {d.name for d in declarations if d.sig_type == 'wire'}
    output_names = {d.name for d in declarations if d.sig_type == 'output'}
    assigned_names = set(lhs_seen)

    unassigned = (wire_names | output_names) - assigned_names
    if unassigned:
        raise UnassignedSignalError(
            f"Unassigned signals: {', '.join(sorted(unassigned))}",
            file=filepath
        )

    # Check for extra assignments (LHS not declared)
    declared_names = {d.name for d in declarations}
    extra_assigned = assigned_names - declared_names
    if extra_assigned:
        raise UndefinedNameError(
            f"Assignment to undeclared signal(s): {', '.join(sorted(extra_assigned))}",
            file=filepath
        )

    return declarations, assignments


# =============================================================================
# BENCH Circuit Format Parser
# =============================================================================

def parse_bench_file(filepath: str) -> Tuple[List[SignalDecl], List[Tuple[str, ASTNode]]]:
    """Parse a BENCH format circuit file and return (declarations, assignments).

    BENCH is a scalar-only format commonly used in circuit benchmarks.

    Returns:
        declarations: List of SignalDecl objects (all scalar)
        assignments: List of (lhs, expression) tuples

    Raises:
        BenchParseError: Syntax error in .bench file
        RedefinitionError: Signal defined multiple times
        UndefinedNameError: Undefined name referenced
    """
    with open(filepath, 'r') as f:
        lines = f.readlines()

    declarations: List[SignalDecl] = []
    assignments: List[Tuple[str, ASTNode]] = []

    # Track all signals (inputs, wires, outputs)
    signal_names: Set[str] = set()
    input_names: Set[str] = set()
    output_names: Set[str] = set()
    wire_names: Set[str] = set()

    # Track assigned signals (for RedefinitionError)
    assigned_lhs: Set[str] = set()

    # For expression parsing
    op_arity = {
        'NOT': 1,
        'BUF': 1,
        'AND': 2,
        'OR': 2,
        'XOR': 2,
        'NAND': 2,
        'NOR': 2,
        'XNOR': 2,
    }

    for line_num, line in enumerate(lines, 1):
        line = line.rstrip('\n\r')

        # Strip comment
        if '#' in line:
            line = line[:line.index('#')]

        # Skip empty lines
        stripped = line.strip()
        if not stripped:
            continue

        # Remove all whitespace for easier parsing
        no_whitespace = ''.join(stripped.split())

        # Check for INPUT(name)
        if no_whitespace.startswith('INPUT(') and no_whitespace.endswith(')'):
            name = no_whitespace[6:-1]  # Remove 'INPUT(' and ')'
            if not name:
                raise BenchParseError(
                    f"Empty input name at line {line_num}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            # Check for brackets (vector support not allowed in BENCH)
            if '[' in name or ']' in name:
                raise BenchParseError(
                    f"Vector notation not allowed in BENCH: {name}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            if name in signal_names:
                raise RedefinitionError(
                    f"Duplicate signal definition: {name}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            signal_names.add(name)
            input_names.add(name)
            declarations.append(SignalDecl(name, 'input', None, None))
            continue

        # Check for OUTPUT(name)
        if no_whitespace.startswith('OUTPUT(') and no_whitespace.endswith(')'):
            name = no_whitespace[7:-1]  # Remove 'OUTPUT(' and ')'
            if not name:
                raise BenchParseError(
                    f"Empty output name at line {line_num}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            if '[' in name or ']' in name:
                raise BenchParseError(
                    f"Vector notation not allowed in BENCH: {name}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            if name in signal_names:
                raise RedefinitionError(
                    f"Duplicate signal definition: {name}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            signal_names.add(name)
            output_names.add(name)
            # Add as output declaration
            declarations.append(SignalDecl(name, 'output', None, None))
            continue

        # Check for assignment: lhs = OP(arg1, arg2, ...)
        if '=' in no_whitespace:
            parts = no_whitespace.split('=', 1)
            if len(parts) != 2:
                raise BenchParseError(
                    f"Invalid assignment at line {line_num}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            lhs = parts[0]
            rhs = parts[1]

            # Validate LHS
            if not lhs:
                raise BenchParseError(
                    f"Empty LHS in assignment at line {line_num}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            if '[' in lhs or ']' in lhs:
                raise BenchParseError(
                    f"Vector notation not allowed in BENCH: {lhs}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            # Check for redefinition
            if lhs in assigned_lhs:
                raise RedefinitionError(
                    f"Redefinition of signal: {lhs}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            assigned_lhs.add(lhs)

            # Add as wire if not already declared as input/output
            if lhs not in signal_names:
                signal_names.add(lhs)
                wire_names.add(lhs)
                declarations.append(SignalDecl(lhs, 'wire', None, None))

            # Parse RHS: OP(arg1, arg2, ...)
            # Find operator name
            op_match = None
            for op in op_arity:
                if rhs.startswith(op + '(') and rhs.endswith(')'):
                    op_match = op
                    break

            if op_match is None:
                raise BenchParseError(
                    f"Unknown or malformed operator call: {rhs}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            args_str = rhs[len(op_match)+1:-1]  # Remove OP( and )
            if args_str:
                arg_names = [arg.strip() for arg in args_str.split(',')]
            else:
                arg_names = []

            # Validate argument count
            min_arity = op_arity[op_match]
            if len(arg_names) < min_arity:
                raise BenchParseError(
                    f"Operator {op_match} requires at least {min_arity} operands, got {len(arg_names)}",
                    file=filepath,
                    line=line_num,
                    col=1
                )

            # Check for literals (BENCH doesn't allow literals in RHS)
            for arg in arg_names:
                # Literals: 0, 1, 0b..., 0x..., sized literals
                if arg in ('0', '1'):
                    raise BenchParseError(
                        f"Literals not allowed in BENCH: {arg}",
                        file=filepath,
                        line=line_num,
                        col=1
                    )
                if arg.startswith('0b') or arg.startswith('0x'):
                    raise BenchParseError(
                        f"Literals not allowed in BENCH: {arg}",
                        file=filepath,
                        line=line_num,
                        col=1
                    )
                if re.match(r'^\d+[\'[bBhHdD]', arg):
                    raise BenchParseError(
                        f"Literals not allowed in BENCH: {arg}",
                        file=filepath,
                        line=line_num,
                        col=1
                    )

                # Check for brackets (vector not allowed)
                if '[' in arg or ']' in arg:
                    raise BenchParseError(
                        f"Vector notation not allowed in BENCH: {arg}",
                        file=filepath,
                        line=line_num,
                        col=1
                    )

            # Build AST: OpCall with SignalRef arguments
            args_ast = []
            for arg in arg_names:
                # BENCH is scalar-only, no indices/slices
                args_ast.append(SignalRef(arg))

            expr = OpCall(op_match, args_ast)
            assignments.append((lhs, expr))
            continue

        # If we get here, the line is invalid
        raise BenchParseError(
            f"Invalid statement: {stripped}",
            file=filepath,
            line=line_num,
            col=1
        )

    # Validate OUTPUT references
    for out_name in output_names:
        if out_name not in signal_names:
            raise UndefinedNameError(
                f"OUTPUT references undefined signal: {out_name}",
                file=filepath
            )
        # Also check that OUTPUT is assigned somewhere (either as input or assigned)
        if out_name not in assigned_lhs and out_name not in input_names:
            raise UndefinedNameError(
                f"OUTPUT references undefined signal: {out_name}",
                file=filepath
            )

    # Validate that all assigned signals (except inputs) are defined
    for lhs in assigned_lhs:
        if lhs not in input_names and lhs not in wire_names:
            # Already added as wire, but check consistency
            pass

    # Also: wires must be assigned (already tracked via assigned_lhs)
    for wname in wire_names:
        if wname not in assigned_lhs:
            raise UnassignedSignalError(
                f"Unassigned wire: {wname}",
                file=filepath
            )

    return declarations, assignments


# =============================================================================
# Expression Evaluator (for circuit evaluation)
# =============================================================================

def eval_expression(expr: ASTNode, signal_values: Dict[str, int],
                    signal_widths: Dict[str, int],
                    filepath: str) -> Tuple[int, int]:
    """Evaluate an expression and return (value, width).

    Args:
        expr: AST node to evaluate
        signal_values: Dict mapping signal names to their integer values
        signal_widths: Dict mapping signal names to their widths
        filepath: For error reporting

    Returns:
        Tuple of (value, width)
    """
    if isinstance(expr, SignalRef):
        if expr.name in signal_values:
            # Get the full signal value
            full_value = signal_values[expr.name]
            width = signal_widths[expr.name]

            if expr.msb is None:
                # Scalar reference
                return full_value, 1
            else:
                # Slice or single bit
                if expr.msb >= width or expr.lsb >= width:
                    raise IndexOutOfBoundsError(
                        f"Index {expr.msb}:{expr.lsb} out of bounds for signal {expr.name} (width {width})",
                        file=filepath
                    )
                # Extract bits from lsb to msb
                mask = ((1 << (expr.msb - expr.lsb + 1)) - 1) << expr.lsb
                slice_value = (full_value & mask) >> expr.lsb
                return slice_value, expr.msb - expr.lsb + 1
        else:
            raise UndefinedNameError(
                f"Undefined signal: {expr.name}",
                file=filepath
            )

    elif isinstance(expr, Literal):
        return expr.value, expr.width

    elif isinstance(expr, Concat):
        # Evaluate all parts
        parts_values = []
        total_width = 0
        for part in expr.parts:
            val, width = eval_expression(part, signal_values, signal_widths, filepath)
            parts_values.append((val, width))
            total_width += width

        # Concatenate: first part is MSB
        result = 0
        for val, width in parts_values:
            result = (result << width) | val

        return result, total_width

    elif isinstance(expr, OpCall):
        op = expr.op.upper()
        args_results = []
        for arg in expr.args:
            val, width = eval_expression(arg, signal_values, signal_widths, filepath)
            args_results.append((val, width))

        # Bitwise operators (width-preserving)
        if op in ('NOT', 'BUF'):
            if len(args_results) != 1:
                raise WidthMismatchError(
                    f"Operator {op} requires 1 operand, got {len(args_results)}",
                    file=filepath
                )
            val, width = args_results[0]
            result = (~val) & ((1 << width) - 1) if op == 'NOT' else val
            return result, width

        elif op in ('AND', 'OR', 'XOR', 'NAND', 'NOR', 'XNOR'):
            if len(args_results) < 2:
                raise WidthMismatchError(
                    f"Operator {op} requires at least 2 operands, got {len(args_results)}",
                    file=filepath
                )

            # Check all operands have same width
            first_width = args_results[0][1]
            for val, width in args_results:
                if width != first_width:
                    raise WidthMismatchError(
                        f"Operator {op}: operand widths {width} and {first_width} don't match",
                        file=filepath
                    )

            mask = (1 << first_width) - 1
            result = args_results[0][0]

            if op == 'AND':
                for val, _ in args_results[1:]:
                    result &= val
            elif op == 'OR':
                for val, _ in args_results[1:]:
                    result |= val
            elif op == 'XOR':
                for val, _ in args_results[1:]:
                    result ^= val
            elif op == 'NAND':
                for val, _ in args_results[1:]:
                    result &= val
                result = mask & ~result
            elif op == 'NOR':
                for val, _ in args_results[1:]:
                    result |= val
                result = mask & ~result
            elif op == 'XNOR':
                for val, _ in args_results[1:]:
                    result ^= val
                result = mask & ~result

            return result & mask, first_width

        elif op in ('MUX', 'ITE'):
            if len(args_results) != 3:
                raise ArityError(
                    f"Operator {op} requires 3 operands, got {len(args_results)}",
                    file=filepath
                )

            sel_val, sel_width = args_results[0]
            a_val, a_width = args_results[1]
            b_val, b_width = args_results[2]

            if sel_width != 1:
                raise WidthMismatchError(
                    f"Operator {op}: selector width {sel_width} must be 1",
                    file=filepath
                )
            if a_width != b_width:
                raise WidthMismatchError(
                    f"Operator {op}: operand widths {a_width} and {b_width} don't match",
                    file=filepath
                )

            result = a_val if sel_val else b_val
            return result, a_width

        elif op in ('REDUCE_AND', 'REDUCE_OR', 'REDUCE_XOR'):
            if len(args_results) != 1:
                raise WidthMismatchError(
                    f"Operator {op} requires 1 operand, got {len(args_results)}",
                    file=filepath
                )

            val, width = args_results[0]
            if width < 1:
                raise WidthMismatchError(
                    f"Operator {op}: operand width {width} must be >= 1",
                    file=filepath
                )

            mask = (1 << width) - 1
            val &= mask

            if op == 'REDUCE_AND':
                # Check if all bits are 1
                result = 1 if val == mask else 0
            elif op == 'REDUCE_OR':
                result = 1 if val != 0 else 0
            else:  # REDUCE_XOR
                result = bin(val & mask).count('1') % 2

            return result, 1

        elif op == 'EQ':
            if len(args_results) != 2:
                raise ArityError(
                    f"Operator EQ requires 2 operands, got {len(args_results)}",
                    file=filepath
                )

            a_val, a_width = args_results[0]
            b_val, b_width = args_results[1]

            if a_width != b_width:
                raise WidthMismatchError(
                    f"Operator EQ: operand widths {a_width} and {b_width} don't match",
                    file=filepath
                )

            return int(a_val == b_val), 1

        else:
            raise ArityError(
                f"Unknown operator: {op}",
                file=filepath
            )

    else:
        raise ValueError(f"Unknown AST node type: {type(expr)}")


def parse_input_literal(value_str: str, expected_width: int,
                        filepath: str, line: int = None, col: int = None) -> int:
    """Parse an input literal value and return the integer value.

    Validates that the width matches the expected width.
    """
    if value_str in ('0', '1'):
        if expected_width != 1:
            raise InputWidthMismatchError(
                f"Input width mismatch: got 1 but expected {expected_width}",
                file=filepath, line=line, col=col
            )
        return int(value_str)

    elif value_str.startswith('0b'):
        bits = value_str[2:]
        if not bits:
            raise InputValueParseError(
                f"Binary literal must have at least one digit",
                file=filepath, line=line, col=col
            )
        value = int(bits, 2)
        width = len(bits)

        if width != expected_width:
            raise InputWidthMismatchError(
                f"Input width mismatch: got {width} but expected {expected_width}",
                file=filepath, line=line, col=col
            )
        return value

    elif value_str.startswith('0x'):
        hex_digits = value_str[2:]
        if not hex_digits:
            raise InputValueParseError(
                f"Hex literal must have at least one digit",
                file=filepath, line=line, col=col
            )
        value = int(hex_digits, 16)
        width = len(hex_digits) * 4

        if width != expected_width:
            raise InputWidthMismatchError(
                f"Input width mismatch: got {width} but expected {expected_width}",
                file=filepath, line=line, col=col
            )
        return value

    else:
        # Sized literal: 8'b1010, 8'hff, 8'd200
        match = re.match(r'(\d+)\'[bBhHdD]([\d01a-fA-F_]+)', value_str)
        if match:
            width = int(match.group(1))
            radix_str = match.group(2).lower()
            value_str_clean = match.group(3).replace('_', '')

            if width != expected_width:
                raise InputWidthMismatchError(
                    f"Input width mismatch: got {width} but expected {expected_width}",
                    file=filepath, line=line, col=col
                )

            try:
                if radix_str == 'b':
                    value = int(value_str_clean, 2)
                elif radix_str == 'h':
                    value = int(value_str_clean, 16)
                else:  # 'd'
                    value = int(value_str_clean, 10)
            except ValueError:
                raise InputValueParseError(
                    f"Invalid literal: {value_str}",
                    file=filepath, line=line, col=col
                )

            if value >= (1 << width):
                raise CircParseError(
                    f"Value {value} too large for {width}-bit literal",
                    file=filepath, line=line, col=col
                )

            return value
        else:
            raise InputValueParseError(
                f"Invalid input literal format: {value_str}",
                file=filepath, line=line, col=col
            )


def format_vector_value(value: int, width: int, radix: str) -> str:
    """Format a vector value according to the specified radix.

    Args:
        value: Integer value
        width: Bit width
        radix: 'bin', 'hex', or 'dec'

    Returns:
        Formatted string
    """
    value &= (1 << width) - 1

    if radix == 'bin':
        return f"0b{value:0{width}b}"
    elif radix == 'hex':
        # Calculate minimum number of hex digits
        hex_digits = (width + 3) // 4
        return f"0x{value:0{hex_digits}x}"
    elif radix == 'dec':
        return str(value)


