            declarations, assignments = parse_bench_file(filepath)
        else:
            raise UnknownInputFormatError(
                f"Unsupported format: {fmt}",
                file=filepath
            )

        result = validate_circ_file(filepath, declarations, assignments)
        inputs = {d.name: d for d in declarations if d.sig_type == 'input'}
        outputs = {d.name: d for d in declarations if d.sig_type == 'output'}
        wires = {d.name: d for d in declarations if d.sig_type == 'wire'}

        # Build dependency graph
        graph: Dict[str, List[str]] = {}
        for lhs, expr in assignments:
            graph[lhs] = get_dependencies(expr)

        # Handle --cone filtering
        cone_outputs = []
        if cone:
            cone_outputs = [name.strip() for name in cone.split(',')]
            # Verify all cone_outputs are valid outputs
            for out_name in cone_outputs:
                if out_name not in outputs:
                    if json_output:
                        print(json.dumps({
                            'ok': False,
                            'command': 'dot',
                            'exit_code': 3,
                            'error': {
                                'type': 'UndefinedNameError',
                                'message': f"unknown output: {out_name}",
                                'file': None,
                                'line': None,
                                'col': None,
                            }
                        }))
                    else:
                        print(f"Error: unknown output: {out_name}", file=sys.stderr)
                    return 3

        # Build reachable set for cone
        def build_reachable_set() -> Set[str]:
            """Build set of signals reachable backward from cone outputs."""
            reachable = set()
            if not cone_outputs:
                # If no cone specified, include everything
                return None

            queue = list(cone_outputs)
            while queue:
                sig = queue.pop(0)
                if sig in reachable:
                    continue
                reachable.add(sig)
                # Add dependencies (reverse graph)
                for lhs, deps in graph.items():
                    if sig in deps:
                        queue.append(lhs)
            return reachable

        reachable = build_reachable_set()

        # Collect nodes and edges for DOT
        nodes_edges = []

        # Map signal to node label
        # Inputs: node id = "in:name", label = "name" or "name[msb:lsb]"
        # Wires/outputs: node id = "sig:name", label = "name" or "name[msb:lsb]"
        # Assignment ops: node id = "op:lhs", label = operator category

        # First, create nodes and edges
        # We'll build the graph from assignments
        for lhs, expr in assignments:
            # Check if this assignment is in the cone (if cone specified)
            if reachable is not None and lhs not in reachable:
                continue

            # Create the operation node
            op_label = get_op_label(expr)
            op_node_id = f"op:{lhs}"

            # Get the LHS signal declaration for label
            if lhs in inputs:
                decl = inputs[lhs]
            elif lhs in wires:
                decl = wires[lhs]
            elif lhs in outputs:
                decl = outputs[lhs]
            else:
                decl = None

            # Signal node label
            if decl and decl.msb is not None:
                sig_label = f"{lhs}[{decl.msb}:{decl.lsb}]"
            else:
                sig_label = lhs

            sig_node_id = f"sig:{lhs}"

            # Add signal node
            nodes_edges.append(f'  "{sig_node_id}" [label="{sig_label}"];')

            # Add edge from op to sig
            nodes_edges.append(f'  "{op_node_id}" -> "{sig_node_id}";')

            # Add edges from dependencies to op
            deps = get_dependencies(expr)
            dep_pairs = set()  # Deduplicate
            for dep in deps:
                # Get base signal name
                base_dep = get_base_signal_name(dep)
                dep_pairs.add((base_dep, op_node_id))

            for base_dep, op_id in sorted(dep_pairs):
                # Determine if dep is input or wire/output
                if base_dep in inputs:
                    dep_node_id = f"in:{base_dep}"
                    # Input node label
                    in_decl = inputs[base_dep]
                    if in_decl.msb is not None:
                        in_label = f"{base_dep}[{in_decl.msb}:{in_decl.lsb}]"
                    else:
                        in_label = base_dep
                    nodes_edges.append(f'  "{dep_node_id}" [label="{in_label}"];')
                else:
                    # Check if it's in cone
                    if reachable is not None and base_dep not in reachable:
                        continue
                    dep_node_id = f"sig:{base_dep}"

                nodes_edges.append(f'  "{dep_node_id}" -> "{op_id}";')

        # Sort all nodes and edges
        nodes_edges.sort()

        # Build DOT content
        dot_lines = ['digraph circopt {']
        dot_lines.extend(nodes_edges)
        dot_lines.append('}')

        # Write to file or stdout
        dot_content = '\n'.join(dot_lines) + '\n'

        if output_file:
            output_path = output_file
        else:
            output_path = None

        if output_file:
            with open(output_file, 'w') as f:
                f.write(dot_content)
            dot_path = output_file
        else:
            # Write to stdout
            print(dot_content)
            dot_path = None

        if json_output:
            result = {
                'ok': True,
                'command': 'dot',
                'dot_path': dot_path if dot_path else None,
            }
            print(json.dumps(result))

        return 0

    except CircuitError as e:
        if json_output:
            print(format_error_json(e, 'dot'))
        else:
            print(f"Error: {e.message}", file=sys.stderr)
        return e.exit_code


# =============================================================================
# 2-Valued Evaluation
# =============================================================================

def cmd_eval(filepath: str, set_inputs: List[str], default: Optional[int],
             allow_extra: bool, json_output: bool, radix: str, mode: str,
             format_flag: str) -> int:
    """Execute eval command with vector support."""

    # Check file exists
    if not os.path.exists(filepath):
        if json_output:
            print(json.dumps({
                'ok': False,
                'command': 'eval',
                'exit_code': 1,
                'error': {
                    'type': 'FileNotFoundError',
                    'message': f"File not found: {filepath}",
                    'file': filepath,
                    'line': None,
                    'col': None,
                }
            }))
        else:
            print(f"Error: File not found: {filepath}", file=sys.stderr)
        return 1

    try:
        fmt = detect_format(filepath, format_flag)

        if fmt == 'circ':
            declarations, assignments = parse_circ_file(filepath)
        elif fmt == 'json':
            declarations, assignments = parse_json_file(filepath)
        elif fmt == 'bench':
            declarations, assignments = parse_bench_file(filepath)
        else:
            raise UnknownInputFormatError(
                f"Unsupported format: {fmt}",
                file=filepath
            )

        result_info = validate_circ_file(filepath, declarations, assignments)
    except CircuitError as e:
        if json_output:
            print(format_error_json(e, 'eval'))
        else:
            print(f"Error: {e.message}", file=sys.stderr)
        return e.exit_code

    # Check radix restriction for 3val mode
    if mode == '3val' and radix != 'bin':
        error = RadixNotAllowedIn3ValError(
            f"Radix {radix} not allowed in 3-valued mode",
            file=filepath
        )
        if json_output:
            print(format_error_json(error, 'eval'))
        else:
            print(f"Error: {error.message}", file=sys.stderr)
        return error.exit_code

    # Build signal width lookup
    signal_widths = {}
    for decl in declarations:
        signal_widths[decl.name] = decl.width

    # Parse input assignments
    input_values = {}
    for assignment in set_inputs:
        if '=' not in assignment:
            if json_output:
                print(json.dumps({
                    'ok': False,
                    'command': 'eval',
                    'exit_code': 2,
                    'error': {
                        'type': 'InputValueParseError',
                        'message': f"Invalid input format: {assignment}. Expected name=value",
                        'file': None,
                        'line': None,
                        'col': None,
                    }
                }))
            else:
                print(f"Error: Invalid input format: {assignment}. Expected name=value", file=sys.stderr)
            return 2

        name, value_str = assignment.split('=', 1)
        name = name.strip()
        value_str = value_str.strip()

        # Get expected width for this input
        expected_width = signal_widths.get(name)
        if expected_width is None:
            if not allow_extra:
                if json_output:
                    print(json.dumps({
                        'ok': False,
                        'command': 'eval',
                        'exit_code': 1,
                        'error': {
                            'type': 'UnknownInputError',
                            'message': f"Unknown input: {name}",
                            'file': None,
                            'line': None,
                            'col': None,
                        }
                    }))
                else:
                    print(f"Error: Unknown input: {name}", file=sys.stderr)
                return 1
            # Allow extra inputs if --allow-extra is set
            # We'll just store as-is with width 1 for now
            # but we need width for evaluation
            input_values[name] = int(value_str)  # Just try to parse as int for simplicity
            continue

        try:
            value = parse_input_literal(value_str, expected_width, filepath)
            input_values[name] = value
        except InputWidthMismatchError as e:
            if json_output:
                print(format_error_json(e, 'eval'))
            else:
                print(f"Error: {e.message}", file=sys.stderr)
            return e.exit_code
        except InputValueParseError as e:
            if json_output:
                print(format_error_json(e, 'eval'))
            else:
                print(f"Error: {e.message}", file=sys.stderr)
            return e.exit_code

    # Get declared input names
    declared_inputs = {d.name for d in declarations if d.sig_type == 'input'}

    # Check for missing inputs
    missing_inputs = declared_inputs - set(input_values.keys())
    if missing_inputs:
        if default is None:
            if json_output:
                print(json.dumps({
                    'ok': False,
                    'command': 'eval',
                    'exit_code': 1,
                    'error': {
                        'type': 'MissingInputError',
                        'message': f"Missing inputs: {', '.join(sorted(missing_inputs))}",
                        'file': None,
                        'line': None,
                        'col': None,
                    }
                }))
            else:
                print(f"Error: Missing inputs: {', '.join(sorted(missing_inputs))}", file=sys.stderr)
            return 1
        else:
            # Fill missing inputs with default value
            for name in missing_inputs:
                width = signal_widths[name]
                # Fill with all bits set to default
                input_values[name] = default * ((1 << width) - 1)

    # Build dependency graph for topological evaluation
    graph: Dict[str, List[str]] = {}
    for lhs, expr in assignments:
        graph[lhs] = []
        # Collect dependencies
        def collect_deps(node: ASTNode):
            if isinstance(node, SignalRef):
                if node.name not in ('0', '1'):
                    graph[lhs].append(node.name)
            elif isinstance(node, Concat):
                for part in node.parts:
                    collect_deps(part)
            elif isinstance(node, OpCall):
                for arg in node.args:
                    collect_deps(arg)

        collect_deps(expr)

    # Evaluate in topological order
    # Process assignments repeatedly until all are computed
    values = dict(input_values)  # Start with input values

    max_iterations = len(assignments) * 10  # Safety limit
    for _ in range(max_iterations):
        progress = False
        for lhs, expr in assignments:
            if lhs in values:
                continue  # Already computed

            if all(dep in values for dep in graph[lhs]):
                val, width = eval_expression(expr, values, signal_widths, filepath)
                values[lhs] = val
                progress = True

        if not progress:
            break

    # Check for uncomputed values (cycles or missing dependencies)
    for lhs, _ in assignments:
        if lhs not in values:
            # Find what's missing
            for dep in graph[lhs]:
                if dep not in values:
                    raise CycleError(
                        f"Cannot evaluate: missing dependency {dep} for {lhs}",
                        file=filepath
                    )

    # Get output values
    outputs = []
    for out_info in result_info['outputs']:
        out_name = out_info['name']
        width = signal_widths[out_name]
        value = values.get(out_name, 0)

        if width == 1:
            # Scalar output: always show 0 or 1
            formatted = str(value & 1)
        else:
            # Vector output: use specified radix
            formatted = format_vector_value(value, width, radix)

        outputs.append({
            'name': out_name,
            'msb': out_info['msb'],
            'lsb': out_info['lsb'],
            'value': formatted
        })

    # Sort outputs by name
    outputs.sort(key=lambda x: x['name'])

    # Output results
    if json_output:
        print(json.dumps({
            'ok': True,
            'command': 'eval',
            'mode': '2val',
            'radix': radix,
            'outputs': outputs
        }))
    else:
        for out in outputs:
            print(f"{out['name']}={out['value']}")

    return 0


def json_cli_error(command: str, error_type: str, message: str) -> None:
    """Print JSON error for CLI errors."""
    print(json.dumps({
        'ok': False,
        'command': command,
        'exit_code': 1,
        'error': {
            'type': error_type,
            'message': message,
            'file': None,
            'line': None,
            'col': None,
        }
    }))


def main():
    import argparse

    parser = argparse.ArgumentParser(
        prog='circopt',
        description='Circuit optimizer',
        add_help=False,
    )
    parser.add_argument('--help', action='store_true', default=False, dest='help_flag')
    parser.add_argument('--version', action='store_true', default=False, dest='version_flag')
    parser.add_argument('--json', action='store_true', default=False, dest='json_flag')
    parser.add_argument('--format', action='store', default='auto',
                        choices=['auto', 'circ', 'json', 'bench'],
                        dest='format_flag',
                        help='Input format: auto, circ, json, or bench')

    # Parse known args first (global flags)
    namespace, remaining = parser.parse_known_args()

    # Check for help/version flags
    if namespace.help_flag:
        print("Usage: circopt [OPTIONS] <COMMAND> [ARGS]")
        print("")
        print("Options:")
        print("  --help, -h      Show this help message")
        print("  --version, -v   Show version information")
        print("  --json          Output as JSON")
        print("  --format        Input format: auto, circ, json, or bench (default: auto)")
        print("")
        print("Commands:")
        print("  check <file>    Parse and validate a circuit file")
        print("  eval <file>     Evaluate circuit with given inputs")
        print("  stats <file>    Compute circuit metrics and statistics")
        print("  lint <file>     Check for warnings about potential issues")
        print("  dot <file> -o <dot_file>  Export circuit as Graphviz DOT")
        return 0

    if namespace.version_flag:
        if namespace.json_flag:
            print(format_version_json())
        else:
            print(VERSION)
        return 0

    # Parse remaining args for command and file
    if not remaining:
        if namespace.json_flag:
            json_cli_error('__cli__', 'CliUsageError', 'No command specified')
        else:
            print("Error: No command specified", file=sys.stderr)
            print("Use --help for usage information", file=sys.stderr)
        return 1

    # The first non-option is the command
    command = remaining[0]

    # Find the file argument (second arg, or after -- if present)
    args_after_command = remaining[1:]
    file_arg = None

    for arg in args_after_command:
        if not arg.startswith('-'):
            file_arg = arg
            break

    # Handle commands
    if command == 'check':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('check', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1
        return cmd_check(file_arg, namespace.json_flag, namespace.format_flag)

    elif command == 'stats':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('stats', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1
        return cmd_stats(file_arg, namespace.json_flag, namespace.format_flag)

    elif command == 'lint':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('lint', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1

        # Parse lint-specific arguments
        max_input_bits = 16

        i = 0
        while i < len(args_after_command):
            arg = args_after_command[i]
            if arg == '--max-input-bits' and i + 1 < len(args_after_command):
                try:
                    max_input_bits = int(args_after_command[i + 1])
                    if max_input_bits < 0:
                        if namespace.json_flag:
                            json_cli_error('lint', 'CliUsageError', f"Invalid max-input-bits: {max_input_bits}. Must be >= 0")
                        else:
                            print(f"Error: Invalid max-input-bits: {max_input_bits}. Must be >= 0", file=sys.stderr)
                        return 1
                except ValueError:
                    if namespace.json_flag:
                        json_cli_error('lint', 'CliUsageError', f"Invalid max-input-bits: {args_after_command[i + 1]}. Must be an integer")
                    else:
                        print(f"Error: Invalid max-input-bits: {args_after_command[i + 1]}. Must be an integer", file=sys.stderr)
                    return 1
                i += 2
            elif arg == file_arg:
                i += 1
            else:
                i += 1

        return cmd_lint(file_arg, namespace.json_flag, namespace.format_flag, max_input_bits)

    elif command == 'dot':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('dot', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1

        # Parse dot-specific arguments
        output_file = None
        cone = None

        i = 0
        while i < len(args_after_command):
            arg = args_after_command[i]
            if arg == '-o' and i + 1 < len(args_after_command):
                output_file = args_after_command[i + 1]
                i += 2
            elif arg == '--cone' and i + 1 < len(args_after_command):
                cone = args_after_command[i + 1]
                i += 2
            elif arg == file_arg:
                i += 1
            else:
                i += 1

        return cmd_dot(file_arg, namespace.json_flag, namespace.format_flag, output_file, cone)

    elif command == 'eval':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('eval', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1

        # Parse eval-specific arguments
        set_inputs = []
        default = None
        allow_extra = False
        radix = 'bin'
        mode = '2val'

        i = 0
        while i < len(args_after_command):
            arg = args_after_command[i]
            if arg == '--set' and i + 1 < len(args_after_command):
                set_inputs.append(args_after_command[i + 1])
                i += 2
            elif arg == '--default' and i + 1 < len(args_after_command):
                val = args_after_command[i + 1]
                if val == '0':
                    default = 0
                elif val == '1':
                    default = 1
                else:
                    if namespace.json_flag:
                        json_cli_error('eval', 'InputValueParseError', f"Invalid default value: {val}. Must be 0 or 1")
                    else:
                        print(f"Error: Invalid default value: {val}. Must be 0 or 1", file=sys.stderr)
                    return 2
                i += 2
            elif arg == '--allow-extra':
                allow_extra = True
                i += 1
            elif arg == '--radix' and i + 1 < len(args_after_command):
                radix_val = args_after_command[i + 1]
                if radix_val in ('bin', 'hex', 'dec'):
                    radix = radix_val
                else:
                    if namespace.json_flag:
                        json_cli_error('eval', 'CliUsageError', f"Invalid radix: {radix_val}. Must be bin, hex, or dec")
                    else:
                        print(f"Error: Invalid radix: {radix_val}. Must be bin, hex, or dec", file=sys.stderr)
                    return 1
                i += 2
            elif arg == '--mode' and i + 1 < len(args_after_command):
                mode_val = args_after_command[i + 1]
                if mode_val in ('2val', '3val'):
                    mode = mode_val
                else:
                    if namespace.json_flag:
                        json_cli_error('eval', 'CliUsageError', f"Invalid mode: {mode_val}. Must be 2val or 3val")
                    else:
                        print(f"Error: Invalid mode: {mode_val}. Must be 2val or 3val", file=sys.stderr)
                    return 1
                i += 2
            elif arg == file_arg:
                # Skip the file argument
                i += 1
            else:
                i += 1

        return cmd_eval(file_arg, set_inputs, default, allow_extra, namespace.json_flag, radix, mode, namespace.format_flag)

    else:
        if namespace.json_flag:
            json_cli_error('__cli__', 'CliUsageError', f"Unknown command: {command}")
        else:
            print(f"Error: Unknown command: {command}", file=sys.stderr)
        return 1


if __name__ == '__main__':
    sys.exit(main())

