# Equivalence Command
# =============================================================================

def evaluate_circuit(
    declarations: List[SignalDecl],
    assignments: List[Tuple[str, ASTNode]],
    input_assignment: Dict[str, int],
    filepath: str
) -> Dict[str, int]:
    """Evaluate a circuit with given input values.

    Args:
        declarations: List of SignalDecl objects
        assignments: List of (lhs, expression) tuples
        input_assignment: Dict mapping input names to their values
        filepath: For error reporting

    Returns:
        Dict mapping all assigned signal names to their values
    """
    # Build signal lookup
    all_signals: Dict[str, SignalDecl] = {}
    inputs: Dict[str, SignalDecl] = {}
    wires: Dict[str, SignalDecl] = {}
    outputs: Dict[str, SignalDecl] = {}

    for decl in declarations:
        all_signals[decl.name] = decl
        if decl.sig_type == 'input':
            inputs[decl.name] = decl
        elif decl.sig_type == 'wire':
            wires[decl.name] = decl
        elif decl.sig_type == 'output':
            outputs[decl.name] = decl

    # Build dependency graph
    def get_deps(node: ASTNode) -> Set[str]:
        deps = set()
        if isinstance(node, SignalRef):
            if node.name not in ('0', '1'):
                deps.add(node.name)
        elif isinstance(node, Concat):
            for part in node.parts:
                deps.update(get_deps(part))
        elif isinstance(node, OpCall):
            for arg in node.args:
                deps.update(get_deps(arg))
        return deps

    graph: Dict[str, List[str]] = {}
    for lhs, expr in assignments:
        graph[lhs] = list(get_deps(expr))

    # Build signal width lookup
    signal_widths = {name: decl.width for name, decl in all_signals.items()}

    # Evaluate in topological order
    values = dict(input_assignment)

    max_iterations = len(assignments) * 10
    for _ in range(max_iterations):
        progress = False
        for lhs, expr in assignments:
            if lhs in values:
                continue
            deps = graph.get(lhs, [])
            if all(dep in values for dep in deps):
                val, _ = eval_expression(expr, values, signal_widths, filepath)
                values[lhs] = val
                progress = True

        if not progress:
            break

    return values


def cmd_equiv(filepath_a: str, filepath_b: str, max_input_bits: int,
              trials: int, output_names: Optional[str], json_output: bool,
              format_flag_a: str, format_flag_b: str, seed: Optional[int]) -> int:
    """Execute equiv command."""
    # Check files exist
    for fp in [filepath_a, filepath_b]:
        if not os.path.exists(fp):
            if json_output:
                print(format_error_json(
                    FileNotFoundError(f"File not found: {fp}", fp),
                    'equiv'
                ))
            else:
                print(f"Error: File not found: {fp}", file=sys.stderr)
            return 1

    try:
        # Parse both circuits
        fmt_a = detect_format(filepath_a, format_flag_a)
        fmt_b = detect_format(filepath_b, format_flag_b)

        if fmt_a == 'circ':
            declarations_a, assignments_a = parse_circ_file(filepath_a)
        elif fmt_a == 'json':
            declarations_a, assignments_a = parse_json_file(filepath_a)
        elif fmt_a == 'bench':
            declarations_a, assignments_a = parse_bench_file(filepath_a)
        else:
            raise UnknownInputFormatError(f"Unsupported format: {fmt_a}", file=filepath_a)

        if fmt_b == 'circ':
            declarations_b, assignments_b = parse_circ_file(filepath_b)
        elif fmt_b == 'json':
            declarations_b, assignments_b = parse_json_file(filepath_b)
        elif fmt_b == 'bench':
            declarations_b, assignments_b = parse_bench_file(filepath_b)
        else:
            raise UnknownInputFormatError(f"Unsupported format: {fmt_b}", file=filepath_b)

        # Validate and get port information
        info_a = validate_circ_file(filepath_a, declarations_a, assignments_a)
        info_b = validate_circ_file(filepath_b, declarations_b, assignments_b)

        # Build signal lookup for both circuits
        def build_signal_map(declarations: List[SignalDecl]) -> Tuple[Dict[str, SignalDecl], Dict[str, SignalDecl], Dict[str, SignalDecl]]:
            inputs = {}
            outputs = {}
            wires = {}
            for decl in declarations:
                if decl.sig_type == 'input':
                    inputs[decl.name] = decl
                elif decl.sig_type == 'output':
                    outputs[decl.name] = decl
                elif decl.sig_type == 'wire':
                    wires[decl.name] = decl
            return inputs, outputs, wires

        inputs_a, outputs_a, wires_a = build_signal_map(declarations_a)
        inputs_b, outputs_b, wires_b = build_signal_map(declarations_b)

        # Check port compatibility
        # Inputs must match exactly: same names, same msb, same lsb
        def ports_match(inputs1: Dict[str, SignalDecl], inputs2: Dict[str, SignalDecl]) -> bool:
            if set(inputs1.keys()) != set(inputs2.keys()):
                return False
            for name in inputs1:
                d1 = inputs1[name]
                d2 = inputs2[name]
                if d1.msb != d2.msb or d1.lsb != d2.lsb:
                    return False
            return True

        if not ports_match(inputs_a, inputs_b):
            raise PortMismatchError(
                "Input ports don't match between circuits"
            )

        # Determine which outputs to compare
        compare_outputs = set()
        if output_names:
            compare_outputs = set(output_names.split(','))
            # Verify all specified outputs exist
            for out_name in compare_outputs:
                if out_name not in outputs_a:
                    raise UndefinedNameError(f"Output '{out_name}' not found in circuit A")
                if out_name not in outputs_b:
                    raise UndefinedNameError(f"Output '{out_name}' not found in circuit B")
        else:
            # Compare all outputs
            # Check that output sets match
            if set(outputs_a.keys()) != set(outputs_b.keys()):
                raise PortMismatchError(
                    "Output ports don't match between circuits"
                )
            compare_outputs = set(outputs_a.keys())

        # Verify output widths match for comparison
        for out_name in compare_outputs:
            if outputs_a[out_name].width != outputs_b[out_name].width:
                raise PortMismatchError(
                    f"Output '{out_name}' has different widths: {outputs_a[out_name].width} vs {outputs_b[out_name].width}"
                )

        # Calculate total input bits
        total_input_bits = sum(d.width for d in inputs_a.values())

        # Determine method
        if total_input_bits <= max_input_bits:
            method = "exhaustive"
            num_comparisons = 1 << total_input_bits
        else:
            method = "randomized"
            num_comparisons = trials

        # Build sorted input list
        input_names = sorted(inputs_a.keys())

        # Build assignments map
        assignment_map_a = {lhs: expr for lhs, expr in assignments_a}
        assignment_map_b = {lhs: expr for lhs, expr in assignments_b}

        # Determine which inputs affect the outputs being compared
        # Build reachability from outputs to inputs for each circuit
        def get_input_deps(target_outputs: Set[str], assignment_map: Dict[str, ASTNode]) -> Set[str]:
            """Get set of inputs that affect target outputs."""
            def get_node_deps(node: ASTNode) -> Set[str]:
                deps = set()
                if isinstance(node, SignalRef):
                    if node.name not in ('0', '1'):
                        deps.add(node.name)
                elif isinstance(node, Concat):
                    for part in node.parts:
                        deps.update(get_node_deps(part))
                elif isinstance(node, OpCall):
                    for arg in node.args:
                        deps.update(get_node_deps(arg))
                return deps

            reachable = set()
            queue = list(target_outputs)

            while queue:
                sig = queue.pop(0)
                if sig in reachable:
                    continue
                reachable.add(sig)

                if sig in assignment_map:
                    expr = assignment_map[sig]
                    for dep in get_node_deps(expr):
                        if dep not in reachable:
                            queue.append(dep)

            # Return only inputs
            return reachable & set(inputs_a.keys())

        relevant_inputs_a = get_input_deps(compare_outputs, assignment_map_a)
        relevant_inputs_b = get_input_deps(compare_outputs, assignment_map_b)

        # These should be the same since inputs match
        relevant_inputs = relevant_inputs_a & relevant_inputs_b

        # If no relevant inputs found (constants?), check outputs directly
        if not relevant_inputs:
            # Evaluate both circuits with no inputs (or default)
            values_a = evaluate_circuit(declarations_a, assignments_a, {}, filepath_a)
            values_b = evaluate_circuit(declarations_b, assignments_b, {}, filepath_b)

            # Compare outputs
            mismatches = []
            for out_name in compare_outputs:
                if values_a.get(out_name) != values_b.get(out_name):
                    mismatches.append(out_name)

            if mismatches:
                # Not equivalent - but need a counterexample
                # Use a single input assignment of all zeros
                counterexample_inputs = []
                for inp_name in input_names:
                    decl = inputs_a[inp_name]
                    counterexample_inputs.append({
                        'name': inp_name,
                        'msb': decl.msb,
                        'lsb': decl.lsb,
                        'value': '0'
                    })

                a_outputs = [{'name': out_name, 'msb': outputs_a[out_name].msb,
                             'lsb': outputs_a[out_name].lsb,
                             'value': str(values_a.get(out_name, 0) & 1)}
                            for out_name in sorted(compare_outputs)]
                b_outputs = [{'name': out_name, 'msb': outputs_b[out_name].msb,
                             'lsb': outputs_b[out_name].lsb,
                             'value': str(values_b.get(out_name, 0) & 1)}
                            for out_name in sorted(compare_outputs)]

                if json_output:
                    print(json.dumps({
                        'ok': True,
                        'command': 'equiv',
                        'equivalent': False,
                        'method': method,
                        'comparisons': 1,
                        'counterexample': {
                            'inputs': counterexample_inputs,
                            'outputs_compared': sorted(list(compare_outputs)),
                            'a_outputs': a_outputs,
                            'b_outputs': b_outputs
                        }
                    }))
                else:
                    print(f"Circuits are NOT equivalent")
                return 10

            # Equivalent with 0 comparisons? That seems odd, but handle it
            if json_output:
                print(json.dumps({
                    'ok': True,
                    'command': 'equiv',
                    'equivalent': True,
                    'method': method,
                    'comparisons': 0
                }))
            else:
                print("Circuits are equivalent")
            return 0

        # For exhaustive: iterate through all input combinations
        if method == "exhaustive":
            # Expand bits if needed
            # For now, treat each input as a unit

            num_combinations = 1 << total_input_bits

            for pattern in range(num_combinations):
                # Build input assignment
                input_vals = {}
                bit_pos = 0
                for inp_name in input_names:
                    decl = inputs_a[inp_name]
                    width = decl.width
                    # Extract the bits
                    mask = (1 << width) - 1
                    val = (pattern >> bit_pos) & mask
                    input_vals[inp_name] = val
                    bit_pos += width

                # Evaluate both circuits
                values_a = evaluate_circuit(declarations_a, assignments_a, input_vals, filepath_a)
                values_b = evaluate_circuit(declarations_b, assignments_b, input_vals, filepath_b)

                # Compare outputs
                for out_name in sorted(compare_outputs):
                    if values_a.get(out_name) != values_b.get(out_name):
                        # Found mismatch - generate counterexample
                        # Build counterexample in proper format
                        counterexample_inputs = []
                        for inp_name in input_names:
                            decl = inputs_a[inp_name]
                            val = input_vals[inp_name]
                            if decl.width == 1:
                                val_str = str(val & 1)
                            else:
                                val_str = format_vector_value(val, decl.width, 'bin')
                            counterexample_inputs.append({
                                'name': inp_name,
                                'msb': decl.msb,
                                'lsb': decl.lsb,
                                'value': val_str
                            })

                        a_outputs = [{'name': out_name, 'msb': outputs_a[out_name].msb,
                                     'lsb': outputs_a[out_name].lsb,
                                     'value': format_vector_value(values_a.get(out_name, 0),
                                                                  outputs_a[out_name].width, 'bin')}
                                    for out_name in sorted(compare_outputs)]
                        b_outputs = [{'name': out_name, 'msb': outputs_b[out_name].msb,
                                     'lsb': outputs_b[out_name].lsb,
                                     'value': format_vector_value(values_b.get(out_name, 0),
                                                                  outputs_b[out_name].width, 'bin')}
                                    for out_name in sorted(compare_outputs)]

                        if json_output:
                            print(json.dumps({
                                'ok': True,
                                'command': 'equiv',
                                'equivalent': False,
                                'method': method,
                                'comparisons': pattern + 1,
                                'counterexample': {
                                    'inputs': counterexample_inputs,
                                    'outputs_compared': sorted(list(compare_outputs)),
                                    'a_outputs': a_outputs,
                                    'b_outputs': b_outputs
                                }
                            }))
                        else:
                            print(f"Circuits are NOT equivalent (counterexample at input combination {pattern})")
                        return 10

            # All combinations matched
            if json_output:
                print(json.dumps({
                    'ok': True,
                    'command': 'equiv',
                    'equivalent': True,
                    'method': method,
                    'comparisons': num_combinations
                }))
            else:
                print("Circuits are equivalent")
            return 0

        else:
            # Randomized method
            import random

            # Seed for reproducibility
            if seed is not None:
                random.seed(seed)

            for i in range(trials):
                # Generate random input assignment
                input_vals = {}
                for inp_name in input_names:
                    decl = inputs_a[inp_name]
                    width = decl.width
                    # Generate random value with correct width
                    val = random.getrandbits(width)
                    input_vals[inp_name] = val

                # Evaluate both circuits
                values_a = evaluate_circuit(declarations_a, assignments_a, input_vals, filepath_a)
                values_b = evaluate_circuit(declarations_b, assignments_b, input_vals, filepath_b)

                # Compare outputs
                for out_name in sorted(compare_outputs):
                    if values_a.get(out_name) != values_b.get(out_name):
                        # Found mismatch
                        counterexample_inputs = []
                        for inp_name in input_names:
                            decl = inputs_a[inp_name]
                            val = input_vals[inp_name]
                            if decl.width == 1:
                                val_str = str(val & 1)
                            else:
                                val_str = format_vector_value(val, decl.width, 'bin')
                            counterexample_inputs.append({
                                'name': inp_name,
                                'msb': decl.msb,
                                'lsb': decl.lsb,
                                'value': val_str
                            })

                        a_outputs = [{'name': out_name, 'msb': outputs_a[out_name].msb,
                                     'lsb': outputs_a[out_name].lsb,
                                     'value': format_vector_value(values_a.get(out_name, 0),
                                                                  outputs_a[out_name].width, 'bin')}
                                    for out_name in sorted(compare_outputs)]
                        b_outputs = [{'name': out_name, 'msb': outputs_b[out_name].msb,
                                     'lsb': outputs_b[out_name].lsb,
                                     'value': format_vector_value(values_b.get(out_name, 0),
                                                                  outputs_b[out_name].width, 'bin')}
                                    for out_name in sorted(compare_outputs)]

                        if json_output:
                            print(json.dumps({
                                'ok': True,
                                'command': 'equiv',
                                'equivalent': False,
                                'method': method,
                                'comparisons': i + 1,
                                'counterexample': {
                                    'inputs': counterexample_inputs,
                                    'outputs_compared': sorted(list(compare_outputs)),
                                    'a_outputs': a_outputs,
                                    'b_outputs': b_outputs
                                }
                            }))
                        else:
                            print(f"Circuits are NOT equivalent (counterexample found after {i + 1} trials)")
                        return 10

            # All trials passed - circuits may be equivalent (probabilistic)
            if json_output:
                print(json.dumps({
                    'ok': True,
                    'command': 'equiv',
                    'equivalent': True,
                    'method': method,
                    'comparisons': trials
                }))
            else:
                print(f"Circuits appear equivalent (tested {trials} random input combinations)")
            return 0

    except CircuitError as e:
        if json_output:
            print(format_error_json(e, 'equiv'))
        else:
            print(f"Error: {e.message}", file=sys.stderr)
        return e.exit_code


# =============================================================================
# 2-Valued Evaluation
# =============================================================================

def cmd_eval(filepath: str, set_inputs: List[str], default: Optional[int],
             allow_extra: bool, json_output: bool, radix: str, mode: str,
             format_flag: str) -> int:
    """Execute eval command with vector support."""

    # Check file exists
    if not os.path.exists(filepath):
        if json_output:
            print(json.dumps({
                'ok': False,
                'command': 'eval',
                'exit_code': 1,
                'error': {
                    'type': 'FileNotFoundError',
                    'message': f"File not found: {filepath}",
                    'file': filepath,
                    'line': None,
                    'col': None,
                }
            }))
        else:
            print(f"Error: File not found: {filepath}", file=sys.stderr)
        return 1

    try:
        fmt = detect_format(filepath, format_flag)

        if fmt == 'circ':
            declarations, assignments = parse_circ_file(filepath)
        elif fmt == 'json':
            declarations, assignments = parse_json_file(filepath)
        elif fmt == 'bench':
            declarations, assignments = parse_bench_file(filepath)
        else:
            raise UnknownInputFormatError(
                f"Unsupported format: {fmt}",
                file=filepath
            )

        result_info = validate_circ_file(filepath, declarations, assignments)
    except CircuitError as e:
        if json_output:
            print(format_error_json(e, 'eval'))
        else:
            print(f"Error: {e.message}", file=sys.stderr)
        return e.exit_code

    # Check radix restriction for 3val mode
    if mode == '3val' and radix != 'bin':
        error = RadixNotAllowedIn3ValError(
            f"Radix {radix} not allowed in 3-valued mode",
            file=filepath
        )
        if json_output:
            print(format_error_json(error, 'eval'))
        else:
            print(f"Error: {error.message}", file=sys.stderr)
        return error.exit_code

    # Build signal width lookup
    signal_widths = {}
    for decl in declarations:
        signal_widths[decl.name] = decl.width

    # Parse input assignments
    input_values = {}
    for assignment in set_inputs:
        if '=' not in assignment:
            if json_output:
                print(json.dumps({
                    'ok': False,
                    'command': 'eval',
                    'exit_code': 2,
                    'error': {
                        'type': 'InputValueParseError',
                        'message': f"Invalid input format: {assignment}. Expected name=value",
                        'file': None,
                        'line': None,
                        'col': None,
                    }
                }))
            else:
                print(f"Error: Invalid input format: {assignment}. Expected name=value", file=sys.stderr)
            return 2

        name, value_str = assignment.split('=', 1)
        name = name.strip()
        value_str = value_str.strip()

        # Get expected width for this input
        expected_width = signal_widths.get(name)
        if expected_width is None:
            if not allow_extra:
                if json_output:
                    print(json.dumps({
                        'ok': False,
                        'command': 'eval',
                        'exit_code': 1,
                        'error': {
                            'type': 'UnknownInputError',
                            'message': f"Unknown input: {name}",
                            'file': None,
                            'line': None,
                            'col': None,
                        }
                    }))
                else:
                    print(f"Error: Unknown input: {name}", file=sys.stderr)
                return 1
            # Allow extra inputs if --allow-extra is set
            # We'll just store as-is with width 1 for now
            # but we need width for evaluation
            input_values[name] = int(value_str)  # Just try to parse as int for simplicity
            continue

        try:
            value = parse_input_literal(value_str, expected_width, filepath)
            input_values[name] = value
        except InputWidthMismatchError as e:
            if json_output:
                print(format_error_json(e, 'eval'))
            else:
                print(f"Error: {e.message}", file=sys.stderr)
            return e.exit_code
        except InputValueParseError as e:
            if json_output:
                print(format_error_json(e, 'eval'))
            else:
                print(f"Error: {e.message}", file=sys.stderr)
            return e.exit_code

    # Get declared input names
    declared_inputs = {d.name for d in declarations if d.sig_type == 'input'}

    # Check for missing inputs
    missing_inputs = declared_inputs - set(input_values.keys())
    if missing_inputs:
        if default is None:
            if json_output:
                print(json.dumps({
                    'ok': False,
                    'command': 'eval',
                    'exit_code': 1,
                    'error': {
                        'type': 'MissingInputError',
                        'message': f"Missing inputs: {', '.join(sorted(missing_inputs))}",
                        'file': None,
                        'line': None,
                        'col': None,
                    }
                }))
            else:
                print(f"Error: Missing inputs: {', '.join(sorted(missing_inputs))}", file=sys.stderr)
            return 1
        else:
            # Fill missing inputs with default value
            for name in missing_inputs:
                width = signal_widths[name]
                # Fill with all bits set to default
                input_values[name] = default * ((1 << width) - 1)

    # Build dependency graph for topological evaluation
    graph: Dict[str, List[str]] = {}
    for lhs, expr in assignments:
        graph[lhs] = []
        # Collect dependencies
        def collect_deps(node: ASTNode):
            if isinstance(node, SignalRef):
                if node.name not in ('0', '1'):
                    graph[lhs].append(node.name)
            elif isinstance(node, Concat):
                for part in node.parts:
                    collect_deps(part)
            elif isinstance(node, OpCall):
                for arg in node.args:
                    collect_deps(arg)

        collect_deps(expr)

    # Evaluate in topological order
    # Process assignments repeatedly until all are computed
    values = dict(input_values)  # Start with input values

    max_iterations = len(assignments) * 10  # Safety limit
    for _ in range(max_iterations):
        progress = False
        for lhs, expr in assignments:
            if lhs in values:
                continue  # Already computed

            if all(dep in values for dep in graph[lhs]):
                val, width = eval_expression(expr, values, signal_widths, filepath)
                values[lhs] = val
                progress = True

        if not progress:
            break

    # Check for uncomputed values (cycles or missing dependencies)
    for lhs, _ in assignments:
        if lhs not in values:
            # Find what's missing
            for dep in graph[lhs]:
                if dep not in values:
                    raise CycleError(
                        f"Cannot evaluate: missing dependency {dep} for {lhs}",
                        file=filepath
                    )

    # Get output values
    outputs = []
    for out_info in result_info['outputs']:
        out_name = out_info['name']
        width = signal_widths[out_name]
        value = values.get(out_name, 0)

        if width == 1:
            # Scalar output: always show 0 or 1
            formatted = str(value & 1)
        else:
            # Vector output: use specified radix
            formatted = format_vector_value(value, width, radix)

        outputs.append({
            'name': out_name,
            'msb': out_info['msb'],
            'lsb': out_info['lsb'],
            'value': formatted
        })

    # Sort outputs by name
    outputs.sort(key=lambda x: x['name'])

    # Output results
    if json_output:
        print(json.dumps({
            'ok': True,
            'command': 'eval',
            'mode': '2val',
            'radix': radix,
            'outputs': outputs
        }))
    else:
        for out in outputs:
            print(f"{out['name']}={out['value']}")

    return 0


def json_cli_error(command: str, error_type: str, message: str) -> None:
    """Print JSON error for CLI errors."""
    print(json.dumps({
        'ok': False,
        'command': command,
        'exit_code': 1,
        'error': {
            'type': error_type,
            'message': message,
            'file': None,
            'line': None,
            'col': None,
        }
    }))


def main():
    import argparse

    parser = argparse.ArgumentParser(
        prog='circopt',
        description='Circuit optimizer',
        add_help=False,
    )
    parser.add_argument('--help', action='store_true', default=False, dest='help_flag')
    parser.add_argument('--version', action='store_true', default=False, dest='version_flag')
    parser.add_argument('--json', action='store_true', default=False, dest='json_flag')
    parser.add_argument('--format', action='store', default='auto',
                        choices=['auto', 'circ', 'json', 'bench'],
                        dest='format_flag',
                        help='Input format: auto, circ, json, or bench')
    parser.add_argument('--seed', action='store', type=int, default=None,
                        dest='seed',
                        help='Random seed for reproducible randomized operations')

    # Parse known args first (global flags)
    namespace, remaining = parser.parse_known_args()

    # Check for help/version flags
    if namespace.help_flag:
        print("Usage: circopt [OPTIONS] <COMMAND> [ARGS]")
        print("")
        print("Options:")
        print("  --help, -h      Show this help message")
        print("  --version, -v   Show version information")
        print("  --json          Output as JSON")
        print("  --format        Input format: auto, circ, json, or bench (default: auto)")
        print("")
        print("Commands:")
        print("  check <file>    Parse and validate a circuit file")
        print("  eval <file>     Evaluate circuit with given inputs")
        print("  stats <file>    Compute circuit metrics and statistics")
        print("  lint <file>     Check for warnings about potential issues")
        print("  dot <file> -o <dot_file>  Export circuit as Graphviz DOT")
        return 0

    if namespace.version_flag:
        if namespace.json_flag:
            print(format_version_json())
        else:
            print(VERSION)
        return 0

    # Parse remaining args for command and file
    if not remaining:
        if namespace.json_flag:
            json_cli_error('__cli__', 'CliUsageError', 'No command specified')
        else:
            print("Error: No command specified", file=sys.stderr)
            print("Use --help for usage information", file=sys.stderr)
        return 1

    # The first non-option is the command
    command = remaining[0]

    # Find the file argument (second arg, or after -- if present)
    args_after_command = remaining[1:]
    file_arg = None

    for arg in args_after_command:
        if not arg.startswith('-'):
            file_arg = arg
            break

    # Handle commands
    if command == 'check':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('check', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1
        return cmd_check(file_arg, namespace.json_flag, namespace.format_flag)

    elif command == 'stats':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('stats', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1
        return cmd_stats(file_arg, namespace.json_flag, namespace.format_flag)

    elif command == 'lint':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('lint', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1

        # Parse lint-specific arguments
        max_input_bits = 16

        i = 0
        while i < len(args_after_command):
            arg = args_after_command[i]
            if arg == '--max-input-bits' and i + 1 < len(args_after_command):
                try:
                    max_input_bits = int(args_after_command[i + 1])
                    if max_input_bits < 0:
                        if namespace.json_flag:
                            json_cli_error('lint', 'CliUsageError', f"Invalid max-input-bits: {max_input_bits}. Must be >= 0")
                        else:
                            print(f"Error: Invalid max-input-bits: {max_input_bits}. Must be >= 0", file=sys.stderr)
                        return 1
                except ValueError:
                    if namespace.json_flag:
                        json_cli_error('lint', 'CliUsageError', f"Invalid max-input-bits: {args_after_command[i + 1]}. Must be an integer")
                    else:
                        print(f"Error: Invalid max-input-bits: {args_after_command[i + 1]}. Must be an integer", file=sys.stderr)
                    return 1
                i += 2
            elif arg == file_arg:
                i += 1
            else:
                i += 1

        return cmd_lint(file_arg, namespace.json_flag, namespace.format_flag, max_input_bits)

    elif command == 'dot':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('dot', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1

        # Parse dot-specific arguments
        output_file = None
        cone = None

        i = 0
        while i < len(args_after_command):
            arg = args_after_command[i]
            if arg == '-o' and i + 1 < len(args_after_command):
                output_file = args_after_command[i + 1]
                i += 2
            elif arg == '--cone' and i + 1 < len(args_after_command):
                cone = args_after_command[i + 1]
                i += 2
            elif arg == file_arg:
                i += 1
            else:
                i += 1

        return cmd_dot(file_arg, namespace.json_flag, namespace.format_flag, output_file, cone)

    elif command == 'eval':
        if file_arg is None:
            if namespace.json_flag:
                json_cli_error('eval', 'CliUsageError', 'Missing required argument: <file>')
            else:
                print("Error: Missing required argument: <file>", file=sys.stderr)
            return 1

        # Parse eval-specific arguments
        set_inputs = []
        default = None
        allow_extra = False
        radix = 'bin'
        mode = '2val'

        i = 0
        while i < len(args_after_command):
            arg = args_after_command[i]
            if arg == '--set' and i + 1 < len(args_after_command):
                set_inputs.append(args_after_command[i + 1])
                i += 2
            elif arg == '--default' and i + 1 < len(args_after_command):
                val = args_after_command[i + 1]
                if val == '0':
                    default = 0
                elif val == '1':
                    default = 1
                else:
                    if namespace.json_flag:
                        json_cli_error('eval', 'InputValueParseError', f"Invalid default value: {val}. Must be 0 or 1")
                    else:
                        print(f"Error: Invalid default value: {val}. Must be 0 or 1", file=sys.stderr)
                    return 2
                i += 2
            elif arg == '--allow-extra':
                allow_extra = True
                i += 1
            elif arg == '--radix' and i + 1 < len(args_after_command):
                radix_val = args_after_command[i + 1]
                if radix_val in ('bin', 'hex', 'dec'):
                    radix = radix_val
                else:
                    if namespace.json_flag:
                        json_cli_error('eval', 'CliUsageError', f"Invalid radix: {radix_val}. Must be bin, hex, or dec")
                    else:
                        print(f"Error: Invalid radix: {radix_val}. Must be bin, hex, or dec", file=sys.stderr)
                    return 1
                i += 2
            elif arg == '--mode' and i + 1 < len(args_after_command):
                mode_val = args_after_command[i + 1]
                if mode_val in ('2val', '3val'):
                    mode = mode_val
                else:
                    if namespace.json_flag:
                        json_cli_error('eval', 'CliUsageError', f"Invalid mode: {mode_val}. Must be 2val or 3val")
                    else:
                        print(f"Error: Invalid mode: {mode_val}. Must be 2val or 3val", file=sys.stderr)
                    return 1
                i += 2
            elif arg == file_arg:
                # Skip the file argument
                i += 1
            else:
                i += 1

        return cmd_eval(file_arg, set_inputs, default, allow_extra, namespace.json_flag, radix, mode, namespace.format_flag)

    else:
        if namespace.json_flag:
            json_cli_error('__cli__', 'CliUsageError', f"Unknown command: {command}")
        else:
            print(f"Error: Unknown command: {command}", file=sys.stderr)
        return 1


if __name__ == '__main__':
    sys.exit(main())

